<script lang="ts">import type{CardAsset}from'@simbot/card';import{buildNpcClusters,selectNpcSprite,type NpcCluster}from'./npc-gallery';let{assets,assetUrlFor}:{assets:CardAsset[];assetUrlFor:(asset:CardAsset)=>string|null}=$props(),limit=$state(40),groups=$derived(buildNpcClusters(assets));function initial(group:NpcCluster){return selectNpcSprite(group,group.emotions[0]??'default');}function change(event:Event,group:NpcCluster){const select=event.currentTarget as HTMLSelectElement,sprite=selectNpcSprite(group,select.value),image=select.closest('article')?.querySelector('img');if(sprite&&image){const url=assetUrlFor(sprite.asset);if(url)image.src=url;}}</script>
<section class="gallery"><p>{groups.length}명 · 이미지는 화면 가까이 왔을 때 불러옵니다.</p><div>{#each groups.slice(0,limit) as group(group.charId)}{@const sprite=initial(group)}<article>{#if sprite}{@const url=assetUrlFor(sprite.asset)}{#if url}<img src={url} alt={`${group.charId} ${sprite.emotion}`} loading="lazy" decoding="async"/>{/if}{/if}<strong>{group.charId}</strong><select aria-label={`${group.charId} 감정`} onchange={(event)=>change(event,group)}>{#each group.emotions as emotion}<option value={emotion}>{emotion}</option>{/each}</select><small>{group.sprites.length}장</small></article>{/each}</div>{#if limit<groups.length}<button onclick={()=>limit+=40}>40명 더 보기</button>{/if}</section>
<style>.gallery{display:grid;gap:8px}.gallery>p{margin:0;color:#8e96a5;font-size:11px}.gallery>div{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px}article{display:grid;gap:5px;min-width:0;padding:7px;border:1px solid var(--card-atmosphere-border,#343945);border-radius:7px;background:#181b21}img{width:100%;aspect-ratio:1;object-fit:contain;background:#0d0f13;border-radius:5px}strong{overflow:hidden;text-overflow:ellipsis;font-size:11px}select{min-width:0;background:#101318;color:#ddd;border:1px solid #3b414d;border-radius:4px}small{color:#7f8795}.gallery>button{padding:8px;border:1px solid #3b414d;border-radius:6px;background:#20242c;color:#ddd}</style>
